#include <iostream>

int main()
{
    int arr[20]{};
    int n{};
    std::cin >> n;

    for (int k{ 0 }; k < n; ++k)
        std::cin >> arr[k];

    int i{};
    int j{};
    std::cin >> i >> j;

    int* ptr{ arr };

    std::cout << *(ptr + i) << '\n';
    std::cout << *(ptr + j) << '\n';
    std::cout << (ptr + j) - (ptr + i) << '\n';

    return 0;
}

